<main class="bos-main detail-main">
  <a class="detail-back" href="/beyond-games/">← All Beyond Games</a>
  <section class="detail-hero"><div class="detail-art"><span><?=e((string)$game['icon'])?></span><i></i><i></i><i></i></div><div class="detail-copy"><span class="bos-kicker"><?=e((string)$game['category'])?> · <?=e((string)$game['phase'])?></span><h1><?=e((string)$game['title'])?></h1><p class="tagline"><?=e((string)$game['tagline'])?></p><p><?=e((string)$game['gameplay'])?></p><div class="status-row"><b><?=e((string)$game['status'])?></b><?php if(!empty($game['launch'])):?><b>Launch lineup</b><?php endif;?></div><div class="bos-actions"><?php if(!empty($game['playable'])&&!empty($game['play_url'])):?><a class="bos-btn" href="<?=e((string)$game['play_url'])?>">Play now</a><?php else:?><button class="bos-btn" id="followGame" type="button" data-slug="<?=e((string)$game['slug'])?>">Follow development</button><?php endif;?><?php if(!empty($game['related_url'])):?><a class="bos-btn secondary" href="<?=e((string)$game['related_url'])?>">Open connected Beyond app</a><?php endif;?></div><p class="follow-note" id="followNote" aria-live="polite"></p></div></section>
  <section class="detail-grid"><article><span class="bos-kicker">Core pillars</span><h2>What defines the game</h2><div class="feature-list"><?php foreach($features as $index=>$feature):?><div><span><?=str_pad((string)($index+1),2,'0',STR_PAD_LEFT)?></span><b><?=e((string)$feature)?></b></div><?php endforeach;?></div></article><article><span class="bos-kicker">Development path</span><h2>From concept to launch</h2><ol><li><b>Playable proof</b><span>Validate the core control or decision loop on mobile and PC.</span></li><li><b>Vertical slice</b><span>Build one polished level with final-quality art, sound and onboarding.</span></li><li><b>Beyond ID beta</b><span>Add cloud-save architecture, accessibility and verified achievements.</span></li><li><b>App Store release</b><span>Launch with daily challenges, fair progression and capped rewards.</span></li></ol></article></section>
  <section class="detail-footer"><div><span class="bos-kicker">Beyond Games standard</span><h2>Instant play. Fair systems. Original identity.</h2><p>No pay-to-win mechanics and no endless reward farming. Game progress comes from play, skill and meaningful achievements.</p></div><a class="bos-btn secondary" href="/beyond-games/#all-games">Explore all <?=count($games)?> games</a></section>
</main>
<script>
const follow=document.getElementById('followGame'),note=document.getElementById('followNote');if(follow){const key='beyond-games-following',slug=follow.dataset.slug;let list=JSON.parse(localStorage.getItem(key)||'[]');const sync=()=>{const active=list.includes(slug);follow.textContent=active?'Following development ✓':'Follow development';note.textContent=active?'Saved locally. This title is now on your development watchlist.':''};follow.addEventListener('click',()=>{list=list.includes(slug)?list.filter(x=>x!==slug):[...list,slug];localStorage.setItem(key,JSON.stringify(list));sync()});sync()}
</script>
